r_ktm_book_shrlon_stroiet_wvo_nest_loan.sql:
SELECT tab_loan.LOAN_TYPE_DESCRIPTION, tab_loan.LOAN_CONTRACT_NO, coalesce(tab_loan.PRINCIPAL_BALANCE,0) AS principal_balance, tab_loan.period_payment_amount, coalesce(tab_loan.c_PRINCIPAL_BALANCE,'0') as c_principal_balance FROM sc_mem_m_membership_registered left join (SELECT sc_lon_m_rule.LOAN_TYPE_DESCRIPTION , sc_lon_m_loan_card.LOAN_CONTRACT_NO , loan_det1.PRINCIPAL_BALANCE , to_snumber((loan_det1.PRINCIPAL_BALANCE)::bigint) as c_principal_balance , sc_lon_m_contract.period_payment_amount , loan_det1.loan_payment_date , sc_lon_m_contract.membership_no FROM sc_lon_m_rule ,sc_lon_m_loan_card ,sc_lon_m_loan_card_detail loan_det1 ,sc_lon_m_contract WHERE sc_lon_m_rule.loan_type = sc_lon_m_contract.loan_type and sc_lon_m_contract.loan_contract_no = sc_lon_m_loan_card.loan_contract_no and sc_lon_m_loan_card.loan_contract_no = loan_det1.loan_contract_no
and loan_det1.seq_no = ( select max(loan_det2.seq_no) from sc_lon_m_loan_card_detail loan_det2 where loan_det2.loan_contract_no = loan_det1.loan_contract_no and loan_det2.loan_payment_date <= '!apply_date_1!'
) and loan_det1.principal_balance > 0 ) tab_loan on tab_loan.membership_no = sc_mem_m_membership_registered.membership_no WHERE sc_mem_m_membership_registered.membership_no = {0}
